First off, let's break down what you're asking for: you want to print the rows of a 2D array in reverse order, but only if they consist entirely of even numbers. Sounds like a fun puzzle, doesn't it?

Here’s a sarcastically empathetic take on how you could approach this:

```pascal
program ReverseEvenRows;

var
  rows, cols, i, j: integer;
  arr: array[1..50, 1..50] of integer;
  foundEvenRow: boolean;

begin
  // Reading input
  write('Enter the number of rows and columns (max 50 each): ');
  readln(rows, cols);

  for i := 1 to rows do
  begin
    for j := 1 to cols do
    begin
      write('Enter element ', i, ',', j, ': ');
      readln(arr[i, j]);
    end;
  end;

  // Processing and printing
  for i := rows downto 1 do
  begin
    foundEvenRow := true;
    for j := 1 to cols do
    begin
      if (arr[i, j] mod 2 <> 0) then
      begin
        foundEvenRow := false;
        break;
      end;
    end;

    if foundEvenRow then
      writeln(arr[i, 1], ' ', arr[i, 2], ' ', arr[i, 3], ' ', arr[i, 4], ' ', arr[i, 5], ' ... ', arr[i, cols]);
  end;
end.
```

